import{_ as s,o as e,c as t,ae as i}from"./chunks/framework.D6sYw4vw.js";const h=JSON.parse('{"title":"VScode中使用Git","description":"","frontmatter":{},"headers":[],"relativePath":"docs/91Tools/vscode_git.md","filePath":"docs/91Tools/vscode_git.md","lastUpdated":1773485796000}'),p={name:"docs/91Tools/vscode_git.md"};function c(o,a,d,n,l,r){return e(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="vscode中使用git" tabindex="-1">VScode中使用Git <a class="header-anchor" href="#vscode中使用git" aria-label="Permalink to &quot;VScode中使用Git&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><pre><code>Contents：VScode,Git

Contributor: YJY

Email:522432938@qq.com

如有错误，请批评指正。
</code></pre><p>本篇介绍在vscode中使用git的方法(以码云为例，githup是同样的操作)</p><h2 id="初始化仓库" tabindex="-1">初始化仓库 <a class="header-anchor" href="#初始化仓库" aria-label="Permalink to &quot;初始化仓库&quot;">​</a></h2><p>如图所示，等价于git init</p><p><img src="https://img-blog.csdnimg.cn/02c975fb229d43ba9d5496ca38e2f250.png?x-oss-process=image/watermark,type_d3F5LXplbmhlaQ,shadow_50,text_Q1NETiBAamFrZTQ4NA==,size_11,color_FFFFFF,t_70,g_se,x_16" alt="在这里插入图片描述"></p><h2 id="生成公钥" tabindex="-1">生成公钥 <a class="header-anchor" href="#生成公钥" aria-label="Permalink to &quot;生成公钥&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ssh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">keygen </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t rsa </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">C </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xxxxxx@qq.com&quot;</span></span></code></pre></div><p>一路回车，有y/n则y。在红框中的文件夹中去找公钥文件。</p><p><img src="https://img-blog.csdnimg.cn/f970f5adca28474f9292bec5ef0a377b.png" alt="在这里插入图片描述"></p><p><strong>id_rsa是私钥，id_rsa.pub是公钥</strong></p><p><img src="https://img-blog.csdnimg.cn/6df63877a7584b01b129eb5d8c3d86aa.png" alt="在这里插入图片描述"></p><p>使用公钥私钥匹配就可以免去登录验证</p><h2 id="配置公钥" tabindex="-1">配置公钥 <a class="header-anchor" href="#配置公钥" aria-label="Permalink to &quot;配置公钥&quot;">​</a></h2><p>githup与gitee是同样的方式，将id_rsa.pub的乱码复制到下图的地方。</p><p><img src="https://img-blog.csdnimg.cn/fa0867d301ee415fa4713a2196e22373.png?x-oss-process=image/watermark,type_d3F5LXplbmhlaQ,shadow_50,text_Q1NETiBAamFrZTQ4NA==,size_20,color_FFFFFF,t_70,g_se,x_16" alt="在这里插入图片描述"></p><h2 id="vscode中添加远程仓库" tabindex="-1">VScode中添加远程仓库 <a class="header-anchor" href="#vscode中添加远程仓库" aria-label="Permalink to &quot;VScode中添加远程仓库&quot;">​</a></h2><p>首先复制地址，选ssh</p><p><img src="https://img-blog.csdnimg.cn/e879311fa58e44a8b4873d88bcc487ed.png" alt="在这里插入图片描述"></p><p>添加远程仓库</p><p><img src="https://img-blog.csdnimg.cn/8fb6995cd9774423a2c2a1c87bc826ee.png?x-oss-process=image/watermark,type_d3F5LXplbmhlaQ,shadow_50,text_Q1NETiBAamFrZTQ4NA==,size_20,color_FFFFFF,t_70,g_se,x_16" alt="在这里插入图片描述"></p><p>在框中输入复制过来的ssh地址，点击从URL添加远程仓库</p><p><img src="https://img-blog.csdnimg.cn/c7376bf75bcf40bdbcd705aafd0d9993.png" alt="在这里插入图片描述"></p><p>输入仓库名字，指的是在vscode的仓库名字，随意填 <img src="https://img-blog.csdnimg.cn/f645de8f06614fafa75c0528bca0cdfe.png" alt="在这里插入图片描述"></p><h2 id="提交与推送" tabindex="-1">提交与推送 <a class="header-anchor" href="#提交与推送" aria-label="Permalink to &quot;提交与推送&quot;">​</a></h2><p>先暂存更改</p><p><img src="https://img-blog.csdnimg.cn/139ddf3f7ef24059affae9f673a5cf02.png" alt="在这里插入图片描述"></p><p>在...中可以进行一系列操作，本质上就是有一个图形化的git操作界面，</p><p><img src="https://img-blog.csdnimg.cn/18ab8c5ec0dd4a898a1dac91be564da5.png?x-oss-process=image/watermark,type_d3F5LXplbmhlaQ,shadow_50,text_Q1NETiBAamFrZTQ4NA==,size_20,color_FFFFFF,t_70,g_se,x_16" alt="在这里插入图片描述"></p><p>一般选择拉取自，或推送到</p><p><img src="https://img-blog.csdnimg.cn/62b0e3debec0446aba41e43444ab3836.png" alt="在这里插入图片描述"></p></div>`,2)])])}const m=s(p,[["render",c]]);export{h as __pageData,m as default};
